test_cases.assertion_pseudocode:
routes := echo.Routes()
for each expected_route in ["POST /orgs", "GET /orgs", "GET /orgs/:id", "PATCH /orgs/:id", "DELETE /orgs/:id", "POST /orgs/:id/block", "POST /orgs/:id/unblock", "GET /orgs/:id/members", "PUT /orgs/:id/members/:user_id", "DELETE /orgs/:id/members/:user_id"]:
  assert route_exists(routes, expected_route)
